import{_ as r,H as o,f as l,i}from"./chunks/framework.eFU6Tutu.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"care/greens.md","filePath":"care/greens.md"}'),n={name:"care/greens.md"};function a(d,t,s,e,g,h){return o(),l("div",null,[...t[0]||(t[0]=[i('<h2 id="петрушка" tabindex="-1">Петрушка <a class="header-anchor" href="#петрушка" aria-label="Permalink to &quot;Петрушка {#петрушка}&quot;">​</a></h2><ul><li><strong>Свет:</strong> Яркий рассеянный, 10–12 часов в сутки. Зимой обязательна досветка фитолампой (располагайте лампу на расстоянии 20–30 см от верхушек).</li><li><strong>Полив:</strong> Умеренный, тёплой отстоянной водой. Летом 2–3 раза в неделю, зимой — 1 раз в неделю. Почва должна быть слегка влажной, но не мокрой. Поливайте под корень, не попадая на листья.</li><li><strong>Температура:</strong> 18–22°C. Минимальная — не ниже 12°C. Не ставьте горшок рядом с батареей — горячий сухой воздух вредит растению.</li><li><strong>Влажность:</strong> Любит опрыскивание тёплой водой, особенно в отопительный сезон. Но не переусердствуйте — избыток влаги ведёт к грибкам.</li><li><strong>Подкормка:</strong> Каждые 3–4 недели половиной дозы комплексного удобрения для зелени. С октября по февраль — раз в месяц. Можно чередовать минеральные и органические удобрения.</li></ul><h3 id="проблемы-при-выращивании" tabindex="-1">Проблемы при выращивании <a class="header-anchor" href="#проблемы-при-выращивании" aria-label="Permalink to &quot;Проблемы при выращивании&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Проблема</th><th>Причина</th><th>Решение</th></tr></thead><tbody><tr><td>Медленно всходят семена</td><td>Эфирные масла на оболочке</td><td>Замочить семена на 2–3 дня, меняя воду</td></tr><tr><td>Желтеют листья</td><td>Перелив, нехватка азота или жёсткая вода</td><td>Сократить полив, подкормить азотным удобрением, использовать отстоянную воду</td></tr><tr><td>Вытянутые тонкие стебли</td><td>Мало света</td><td>Переставить на светлое окно или включить фитолампу</td></tr><tr><td>Опадают листья</td><td>Сквозняки или резкие перепады температуры</td><td>Убрать от сквозняков, держать при стабильной температуре</td></tr><tr><td>Пятна на листьях</td><td>Грибковое заболевание</td><td>Обработать фунгицидом, снизить влажность, улучшить вентиляцию</td></tr><tr><td>Замедленный рост</td><td>Нехватка питания или тесный горшок</td><td>Подкормить или пересадить в более просторную ёмкость</td></tr></tbody></table><h3 id="размножение" tabindex="-1">Размножение <a class="header-anchor" href="#размножение" aria-label="Permalink to &quot;Размножение&quot;">​</a></h3><p><strong>Из семян (основной способ):</strong></p><ol><li>Замочите семена в тёплой воде на 2–3 дня, меняя воду 2–3 раза в сутки — это смывает эфирные масла и ускоряет прорастание.</li><li>Посейте семена во влажный грунт на глубину 0.5–1 см, расстояние между семенами — 2–3 см.</li><li>Накройте плёнкой или стеклом, поставьте в тёплое место (18–22°C).</li><li>Всходы появятся через 14–21 день. После этого снимите укрытие.</li><li>Когда появится 2–4 настоящих листа, рассадите растения по отдельным горшкам.</li></ol><p><strong>Из корнеплода (быстрый способ):</strong></p><ol><li>Возьмите здоровый корнеплод петрушки диаметром 2–4 см.</li><li>Посадите его в горшок под углом 45°, оставляя верхушку над поверхностью почвы.</li><li>Поливайте умеренно.</li><li>Зелень появится через 4–6 недель (быстрее, чем из семян).</li></ol><h2 id="мята" tabindex="-1">Мята <a class="header-anchor" href="#мята" aria-label="Permalink to &quot;Мята {#мята}&quot;">​</a></h2><ul><li><strong>Свет:</strong> Яркий рассеянный.</li><li><strong>Полив:</strong> Регулярный, земля не должна пересыхать.</li><li><strong>Температура:</strong> 18-22°C.</li></ul><h3 id="проблемы-при-выращивании-1" tabindex="-1">Проблемы при выращивании <a class="header-anchor" href="#проблемы-при-выращивании-1" aria-label="Permalink to &quot;Проблемы при выращивании&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Проблема</th><th>Причина</th><th>Решение</th></tr></thead><tbody><tr><td>Желтеют листья</td><td>Перелив или недостаток света</td><td>Уменьшить полив, поставить светлее</td></tr><tr><td>Тонкие вытянутые побеги</td><td>Мало света</td><td>Переставить на южное окно</td></tr><tr><td>Коричневые пятна на листьях</td><td>Грибок из-за влаги</td><td>Не опрыскивать, проветривать</td></tr></tbody></table><h3 id="размножение-1" tabindex="-1">Размножение <a class="header-anchor" href="#размножение-1" aria-label="Permalink to &quot;Размножение&quot;">​</a></h3><p>Черенками — поставьте веточку в воду, через неделю появятся корни.</p><h2 id="базилик" tabindex="-1">Базилик <a class="header-anchor" href="#базилик" aria-label="Permalink to &quot;Базилик {#базилик}&quot;">​</a></h2><ul><li><strong>Свет:</strong> Яркий рассеянный, минимум 6 часов в день. Лучше всего южное окно или досветка фитолампой.</li><li><strong>Полив:</strong> Регулярный, земля должна быть слегка влажной. Не заливать — начнётся корневая гниль.</li><li><strong>Температура:</strong> 20–25°C. Не выносит холода и сквозняков.</li><li><strong>Влажность:</strong> Любит опрыскивание, но не часто — чтобы не появился грибок.</li><li><strong>Подкормка:</strong> Раз в 2–3 недели комплексным удобрением для зелени.</li></ul><h3 id="проблемы-при-выращивании-2" tabindex="-1">Проблемы при выращивании <a class="header-anchor" href="#проблемы-при-выращивании-2" aria-label="Permalink to &quot;Проблемы при выращивании&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Проблема</th><th>Причина</th><th>Решение</th></tr></thead><tbody><tr><td>Желтеют и вянут листья</td><td>Перелив или холодная вода</td><td>Поливать умеренно, водой комнатной температуры</td></tr><tr><td>Вытянутые тонкие побеги</td><td>Мало света</td><td>Переставить на светлое окно или включить фитолампу</td></tr><tr><td>Листья мельчают, бледнеют</td><td>Нехватка удобрений</td><td>Подкормить азотным удобрением</td></tr><tr><td>Коричневые или чёрные пятна</td><td>Грибок из-за переувлажнения</td><td>Уменьшить полив, проветривать, удалить больные листья</td></tr><tr><td>Белый налёт</td><td>Мучнистая роса</td><td>Обработать раствором соды, обеспечить циркуляцию воздуха</td></tr></tbody></table><h3 id="размножение-2" tabindex="-1">Размножение <a class="header-anchor" href="#размножение-2" aria-label="Permalink to &quot;Размножение&quot;">​</a></h3><p><strong>Черенками:</strong> срежьте верхушку длиной 10–15 см, поставьте в воду. Корни появляются через 5–10 дней. После этого сажайте в грунт.</p><p><strong>Семенами:</strong> сейте в марте–апреле в рыхлую влажную почву на глубину 0.5 см. Накройте плёнкой до всходов (появляются через 5–10 дней). При появлении 2–3 настоящих листьев рассадите в отдельные горшки.</p><h2 id="укроп" tabindex="-1">Укроп <a class="header-anchor" href="#укроп" aria-label="Permalink to &quot;Укроп {#укроп}&quot;">​</a></h2><p>Укроп имеет свои нюансы, которые помогут получить ароматную зелень:</p><ul><li><strong>Выбор сорта:</strong> Для подоконника выбирайте компактные, желательно позднеспелые сорта (<code>Кибрай</code>, <code>Салют</code>, <code>Аллигатор</code>). Они дольше не зацветают.</li><li><strong>Подготовка семян:</strong> Обязательно замочите семена в тёплой воде на сутки, меняя её несколько раз. Это смоет эфирные масла и ускорит прорастание (всходы появятся через 10-14 дней вместо 3 недель).</li><li><strong>Ёмкость и грунт:</strong> Нужен глубокий горшок (от 1,5 л) с дренажом. Грунт — рыхлый, плодородный, нейтральной кислотности.</li><li><strong>Посев:</strong> Сейте семена во влажный грунт на глубину 1-2 см. До появления всходов накройте плёнкой.</li><li><strong>Полив:</strong> Укроп очень влаголюбив, почва всегда должна быть слегка влажной. При недостатке воды листья грубеют и становятся менее ароматными. Полезно опрыскивать.</li><li><strong>Свет:</strong> Это светолюбивая культура. Зимой обязательна досветка фитолампой (до 14 часов в сутки), иначе стебли вытянутся, а зелени будет мало. Летом притеняйте от прямых полуденных лучей.</li><li><strong>Температура:</strong> Оптимально 15–20°C.</li><li><strong>Сбор урожая:</strong> Укроп не отрастает после полной срезки. Срезайте отдельные крупные листья или ветки, оставляя точку роста. Чтобы зелень была постоянно, подсевайте новые семья каждые 3-4 недели.</li></ul><h2 id="лук" tabindex="-1">Лук (зелёный) <a class="header-anchor" href="#лук" aria-label="Permalink to &quot;Лук (зелёный) {#лук}&quot;">​</a></h2><p>Зелёный лук имеет свои нюансы, которые помогут получить сочные перья без хлопот:</p><ul><li><strong>Выбор способа выращивания:</strong> Самый быстрый — из луковицы (репки или севка). Урожай через 7–10 дней. Из семян (чернушки) дольше (2–3 месяца), но зелень отрастает несколько раз. Многолетние луки (батун, шнитт) растут на одном месте до 3–4 лет.</li><li><strong>Выбор луковицы:</strong> Берите здоровые, плотные луковицы среднего размера, лучше слегка проросшие. Срежьте верхушку на 0.5–1 см — перья пойдут быстрее.</li><li><strong>Ёмкость и грунт:</strong> Подойдёт любой контейнер. При выращивании в воде используйте стакан или банку так, чтобы вода касалась только донца (луковица не должна плавать!). При посадке в грунт заглубляйте луковицу на 2/3, поливайте умеренно.</li><li><strong>Уход в воде:</strong> Меняйте воду каждые 2–3 дня, иначе луковица загниёт. Промывайте корни и ёмкость. Одна луковица даёт 2–3 урожая, затем истощается.</li><li><strong>Уход в грунте:</strong> Полив умеренный, без застоя воды. Свет на первых порах (10–12 дней) не важен, затем поставьте на светлое окно. Температура 18–22°C.</li><li><strong>Свет:</strong> После появления перьев нужен яркий рассеянный свет. Зимой желательна досветка, чтобы перья не были бледными и тонкими.</li><li><strong>Полив:</strong> В грунте — умеренный, не допуская застоя воды. В воде — меняйте воду каждые 2–3 дня.</li><li><strong>Температура:</strong> 18–22°C. При более высокой температуре перья растут быстрее, но становятся тоньше.</li><li><strong>Влажность:</strong> Не требователен, опрыскивать не нужно.</li><li><strong>Подкормка:</strong> При выращивании в грунте можно подкормить комплексным удобрением, если зелень бледная. В воде подкормки не нужны.</li><li><strong>Сбор урожая:</strong> Срезайте перья, когда они достигнут 15–20 см. Не срезайте всё сразу — оставляйте несколько перьев для дальнейшего роста. Луковица в грунте может давать зелень 2–3 месяца.</li></ul><h2 id="салат" tabindex="-1">Салат <a class="header-anchor" href="#салат" aria-label="Permalink to &quot;Салат {#салат}&quot;">​</a></h2><p>Салат имеет свои нюансы, которые помогут получить нежную и сочную зелень:</p><ul><li><strong>Выбор сорта:</strong> Для подоконника выбирайте скороспелые и теневыносливые сорта (<code>Московский парниковый</code>, <code>Балет</code>, <code>Изумрудное кружево</code>, <code>Лолло Росса</code>). Кресс-салат — самый неприхотливый, растёт даже без земли.</li><li><strong>Ёмкость и грунт:</strong> Салату не нужен глубокий горшок — достаточно 10–15 см. Обязателен дренаж. Грунт — рыхлый, питательный, нейтральной кислотности (готовый для рассады).</li><li><strong>Посев:</strong> Сейте семена во влажный грунт на глубину 0.5 см с интервалом 2–3 см. До всходов накройте плёнкой (появляются на 3–5 день). <strong>Ключевой момент:</strong> при появлении 2–3 настоящих листьев обязательно <strong>проредите</strong>, оставляя 5–8 см между растениями. При загущении салат не образует розетки и быстро уходит в стрелку.</li><li><strong>Полив и влажность:</strong> Салат очень влаголюбив. Поливайте часто и обильно (2–3 раза в неделю), не допуская пересыхания почвы. При недостатке влаги листья грубеют и горчат. Полезно опрыскивать растения, особенно при сухом воздухе от батарей.</li><li><strong>Свет:</strong> Салату нужно 12–14 часов света. Зимой обязательна досветка фитолампой, иначе стебли вытянутся, а розетка не сформируется. Летом притеняйте от прямых полуденных лучей.</li><li><strong>Температура:</strong> Оптимально 18–20°C. При более высокой температуре и сухом воздухе листья быстрее грубеют и становятся горькими.</li><li><strong>Сбор урожая:</strong> Начинайте срезать листья, когда растение достигнет 8–10 см (через 3–5 недель). <strong>Не вырывайте с корнем!</strong> Срезайте ножницами 3–4 нижних внешних листа, оставляя сердцевину — кустик продолжит расти и даст ещё 1–2 урожая.</li></ul><h2 id="микрозелень" tabindex="-1">Микрозелень <a class="header-anchor" href="#микрозелень" aria-label="Permalink to &quot;Микрозелень {#микрозелень}&quot;">​</a></h2><p>Микрозелень — это, пожалуй, самая быстрая и технологичная культура для подоконника. Её уход кардинально отличается от обычной зелени.</p><ul><li><p><strong>Что это:</strong> Молодые побеги растений в возрасте 5-14 дней. В пищу идёт стебель и семядольные листья. От проростков отличается тем, что срезается, а не естся целиком с корнем.</p></li><li><p><strong>Выбор семян:</strong> Подходят семена многих культур: редис, брокколи, горчица, подсолнечник, горох, базилик, кресс-салат. <strong>Важно:</strong> Используйте специальные семена для микрозелени или органические (без протравливания химикатами). Обычные семена из садовых центров могут быть обработаны и не подходят для еды в сыром виде.</p></li><li><p><strong>Ёмкость и субстрат:</strong> Подойдёт любой неглубокий пластиковый контейнер (высотой 5-7 см) с дренажными отверстиями. На дно укладывают субстрат:</p><ul><li><em>Самые простые:</em> Марля, вата, бумажные полотенца, сложенные в несколько слоёв.</li><li><em>Специальные:</em> Кокосовое волокно, джутовый коврик, агровата. Микрозелень не нуждается в питательной почве, так как берёт энергию из самого семени.</li></ul></li><li><p><strong>Посев:</strong> Субстрат хорошо увлажняют. Семена сеют <strong>густо</strong>, почти вплотную друг к другу. Сверху слегка присыпать землёй не нужно, но можно накрыть другим влажным слоем субстрата или крышкой для создания парникового эффекта.</p></li><li><p><strong>Условия:</strong> До появления всходов ёмкость держат в тепле и темноте. Как только семена проклюнутся (через 2-4 дня), крышку снимают и контейнер выставляют на свет (окно или под фитолампу). Температура комфортна 22-26°C.</p></li><li><p><strong>Полив:</strong> Важно поддерживать субстрат во влажном состоянии, но не заливать. Лучше всего использовать нижний полив (наливать воду в поддон) или аккуратно опрыскивать из пульверизатора, чтобы не повредить хрупкие ростки. Застой воды и переувлажнение ведут к главному врагу микрозелени — <strong>плесени</strong>.</p></li><li><p><strong>Сбор урожая:</strong> Микрозелень готова, когда высота ростков достигнет 5-10 см и появятся первые настоящие листочки (обычно через 5-14 дней). Срезают урожай ножницами непосредственно перед употреблением, оставляя небольшой пенёк. Повторно микрозелень не отрастает.</p></li></ul>',34)])])}const p=r(n,[["render",a]]);export{u as __pageData,p as default};
